<th>Scholarship Type</th>
<th>Scholarship Rate</th>
</tr>
</thead>
<thead>
<tr>
<td>Koc University</td>
<td>Success Scholarship</td>
<td>25% &#8211; 100%</td>
</tr>
<tr>
<td>Sabancı University</td>
<td>Intrance Scholarship</td>
<td>25% &#8211; 100%</td>
</tr>
